function parse(frame) {
  const bytes = [];
  for (let i = 0; i < frame.length; i += 2) {
    const byte = parseInt(frame.slice(i, i + 2), 16);
    if (!Number.isNaN(byte)) bytes.push(byte);
  }

  const readUInt16LE = (offset) => (bytes[offset] || 0) | ((bytes[offset + 1] || 0) << 8);
  const readUInt32LE = (offset) => ((bytes[offset] || 0) | ((bytes[offset + 1] || 0) << 8) | ((bytes[offset + 2] || 0) << 16) | ((bytes[offset + 3] || 0) << 24)) >>> 0;
  const readSigned24BE = (offset) => {
    let value = ((bytes[offset] || 0) << 16) | ((bytes[offset + 1] || 0) << 8) | (bytes[offset + 2] || 0);
    if (value & 0x800000) value -= 0x1000000;
    return value;
  };
  const pt100 = (code) => {
    const A = 3.9083e-3;
    const B = -5.775e-7;
    const scale = 0.0002980232 / 100;
    const discriminant = (A * A) - (4 * B * (1 - (code * scale)));
    if (discriminant < 0) return NaN;
    return (-A + Math.sqrt(discriminant)) / (2 * B);
  };

  const payloadLen = readUInt16LE(16);
  const validSamples = readUInt16LE(18);
  const channelCount = bytes[3] || 4;
  const sampleBytes = bytes[4] || 3;
  const samplesFromPayload = Math.floor(Math.max(0, payloadLen - 6) / Math.max(1, channelCount * sampleBytes));
  const sampleCount = Math.min(validSamples || samplesFromPayload, samplesFromPayload);
  const vibrationOffset = 36;
  const requiredEnd = vibrationOffset + (channelCount * sampleCount * sampleBytes);

  if (sampleBytes !== 3 || channelCount < 4 || sampleCount <= 0 || bytes.length < requiredEnd) return [];

  const temperatureOffsetC = 5.62;
  const temp1 = pt100(readSigned24BE(30)) + temperatureOffsetC;
  const temp2 = pt100(readSigned24BE(33)) + temperatureOffsetC;
  const lowFrequency = [];
  const general = [];
  const lowFrequencyOffset = vibrationOffset + (2 * sampleCount * sampleBytes);
  const generalOffset = vibrationOffset + (3 * sampleCount * sampleBytes);

  for (let i = 0; i < sampleCount; i++) {
    lowFrequency.push(readSigned24BE(lowFrequencyOffset + i * sampleBytes) * 2.3841858e-6);
    general.push(readSigned24BE(generalOffset + i * sampleBytes) * 1.1920929e-5);
  }

  return {
    title: 'Gearbox Monitoring Data',
    datasets: [
      { index: 0, title: 'Temperature 1', value: temp1 },
      { index: 1, title: 'Temperature 2', value: temp2 },
      { index: 2, title: 'Low-frequency Vibration', value: lowFrequency[lowFrequency.length - 1], buffer: lowFrequency },
      { index: 3, title: 'General Vibration', value: general[general.length - 1], buffer: general }
    ],
    meta: {
      sequence: readUInt32LE(8),
      sampleRate: readUInt32LE(12),
      validSamples: sampleCount,
      payloadLength: payloadLen
    }
  };
}
